from agno.memory import Memory
from vex import verify

@verify(test_name='memory_recall_validation')
def test_memory_integrity(session_history):
    memory = Memory()
    for msg in session_history:
        memory.add(msg)

    recall_check = memory.search('previous decision')

    for recalled in recall_check:
        assert any(
            msg['content'] == recalled.content 
            for msg in session_history
        ), f'Fabricated memory: {recalled.content}'

    return {'memory_valid': True, 'issues': []}

from pydantic import BaseModel
from typing import List
from agno.agent import Agent
from vex import verify

class NestedResponse(BaseModel):
    decisions: List[dict]
    confidence: float

@verify(test_name='schema_validation')
def test_structured_output():
    agent = Agent(
        model='gpt-4o',
        output_type=NestedResponse
    )

    result = agent.run('Analyze this data', output_type=NestedResponse)

    try:
        validated = NestedResponse.model_validate(result)
        return {'valid': True, 'schema': validated.model_dump()}
    except Exception as e:
        return {'valid': False, 'error': str(e)}

