from agno.memory import Memory

class GroundedMemory(Memory):
    def add_with_citation(self, content, citation_id):
        self.add({
            'content': content,
            'citation_id': citation_id,
            'timestamp': datetime.now()
        })

    def search_with_validation(self, query):
        results = self.search(query)
        validated = []
        for result in results:
            if self._verify_citation(result.citation_id):
                validated.append(result)
        return validated

    def _verify_citation(self, citation_id):
        return citation_id in self.all_citations()

from agno.agent import Agent
from pydantic import BaseModel

class SafeStructuredAgent:
    def __init__(self, schema):
        self.schema = schema
        self.agent = Agent(output_type=schema)

    def run_with_retry(self, prompt, max_retries=3):
        for attempt in range(max_retries):
            try:
                result = self.agent.run(prompt)
                validated = self.schema.model_validate(result)
                return validated
            except Exception:
                prompt += f"\n[ATTEMPT {attempt+1}] Ensure response matches schema exactly"
        raise ValueError('Schema validation failed after retries')

