from agno.agent import Agent
from agno.team import Team
from vex import verify, monitor

# Install: pip install agno vex-sdk

@monitor('production-agent-team')
class ObservableAgnoTeam:
    def __init__(self):
        self.vision_agent = Agent(
            name='vision_analyzer',
            model='gpt-4o',
            vision=True
        )
        self.memory_agent = Agent(name='memory_keeper')
        self.team = Team(agents=[self.vision_agent, self.memory_agent])

    @verify(
        test_name='full_agent_workflow',
        assert_vision_grounding=True,
        assert_memory_consistency=True,
        assert_schema_valid=True
    )
    def process_request(self, image_url, conversation_history, schema):
        result = self.team.run(
            inputs={
                'image': image_url,
                'history': conversation_history
            },
            output_type=schema
        )
        return result

# Usage
team = ObservableAgnoTeam()
result = team.process_request(
    image_url='https://example.com/image.jpg',
    conversation_history=[{'role': 'user', 'content': 'Analyze'}],
    schema=NestedResponse
)
